code.Java:
import java.io.*;
public class Main{
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb=new StringBuilder();
        int T=Integer.parseInt(br.readLine().trim());
        for(int tc=0;tc<T;tc++){
            char type=br.readLine().trim().charAt(0);
            String val=br.readLine().trim();
            if(type=='i'){
                sb.append(Integer.parseInt(val)).append('\n');
            }else if(type=='f'){
                float f=Float.parseFloat(val);
                sb.append(String.format("%g",f)).append('\n');
            }else{ // 'c'
                sb.append(val.charAt(0)).append('\n');
            }
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys

def main():
    data=sys.stdin.read().splitlines()
    if not data:
        return
    t=int(data[0].strip())
    out=[]
    idx=1
    for _ in range(t):
        typ=data[idx].strip()[0]
        idx+=1
        val=data[idx].strip()
        idx+=1
        if typ=='i':
            out.append(str(int(val)))
        elif typ=='f':
            out.append('{:g}'.format(float(val)))
        else:
            out.append(val[0])
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    main()

code.JavaScript:
const fs=require('fs');
const lines=fs.readFileSync(0,'utf-8').trim().split('\n');
let idx=0;
const T=parseInt(lines[idx++].trim(),10);
let out=[];
for(let i=0;i<T;i++){
  const type=lines[idx++].trim()[0];
  const valLine=lines[idx++].trim();
  if(type==='i'){
    out.push(parseInt(valLine,10).toString());
  }else if(type==='f'){
    // Use precision similar to %g (6 significant digits)
    let s=Number(valLine).toPrecision(6);
    // Remove unnecessary trailing zeros and dot before exponent if present
    s=s.replace(/\.?(0+)(e|$)/, '$2');
    out.push(s);
  }else{ // 'c'
    out.push(valLine[0]);
  }
}
console.log(out.join('\n'));

